    .ToList();

foreach (var attr in attrs) {
    Console.WriteLine($"  {attr.Namespace}.{attr.Name}");
}

Console.WriteLine("\n=== MCP NAMESPACES ===");
var namespaces = asmPath.GetTypes()
    .Where(t => !string.IsNullOrEmpty(t.Namespace) && t.Namespace.StartsWith("ModelContextProtocol"))
    .Select(t => t.Namespace)
    .Distinct()
    .OrderBy(x => x)
    .ToList();

foreach (var ns in namespaces) {
    Console.WriteLine($"  {ns}");
}

Console.WriteLine("\n=== TOOL/PROMPT/RESOURCE ATTRIBUTES ===");
var toolAttr = asmPath.GetType("ModelContextProtocol.Server.McpServerToolAttribute");
if (toolAttr != null) {
    Console.WriteLine($"  McpServerToolAttribute: {toolAttr.FullName}");
    Console.WriteLine($"    Properties: {string.Join(", ", toolAttr.GetProperties().Select(p => p.Name))}");
}

var promptAttr = asmPath.GetType("ModelContextProtocol.Server.McpServerPromptAttribute");
if (promptAttr != null) {
    Console.WriteLine($"  McpServerPromptAttribute: {promptAttr.FullName}");
    Console.WriteLine($"    Properties: {string.Join(", ", promptAttr.GetProperties().Select(p => p.Name))}");
}

var resourceAttr = asmPath.GetType("ModelContextProtocol.Server.McpServerResourceAttribute");
if (resourceAttr != null) {
    Console.WriteLine($"  McpServerResourceAttribute: {resourceAttr.FullName}");
    Console.WriteLine($"    Properties: {string.Join(", ", resourceAttr.GetProperties().Select(p => p.Name))}");
}

Console.WriteLine("\n=== TYPE-LEVEL ATTRIBUTES ===");
var typeAttrs = asmPath.GetTypes()
    .Where(t => t.Name.EndsWith("TypeAttribute") && t.Namespace == "ModelContextProtocol.Server")
    .OrderBy(t => t.Name)
    .ToList();

foreach (var attr in typeAttrs) {
    Console.WriteLine($"  {attr.Name}");
}

Console.WriteLine("\n=== KEY BUILDER/SERVER TYPES ===");
var keyTypes = new[] {
    "McpServer",
    "McpServerBuilder", 
    "McpServerTool",
    "McpServerPrompt",
    "McpServerResource",
    "McpServerOptions",
    "StdioServerTransport",
    "SseServerTransport"
};

foreach (var typeName in keyTypes) {
    var type = asmPath.GetType($"ModelContextProtocol.Server.{typeName}");
    if (type != null) {
        Console.WriteLine($"  ModelContextProtocol.Server.{typeName}");
    }
}

Console.WriteLine("\n=== DEPENDENCY INJECTION EXTENSIONS ===");
var diTypes = asmPath.GetTypes()
    .Where(t => t.Namespace == "Microsoft.Extensions.DependencyInjection")
    .OrderBy(t => t.Name)
    .ToList();

foreach (var type in diTypes) {
    Console.WriteLine($"  {type.Name}");
}
EOF

