using System;
using System.Reflection;
using System.Linq;
using ModelContextProtocol.Server;
using ModelContextProtocol.Protocol;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;

Console.WriteLine("=== TYPE-LEVEL ATTRIBUTES ===");
var typeAttrs = new[] {
    typeof(McpServerToolTypeAttribute),
    typeof(McpServerPromptTypeAttribute),
    typeof(McpServerResourceTypeAttribute)
};

foreach (var attr in typeAttrs) {
    Console.WriteLine($"\n{attr.Name}:");
    var attrUsage = attr.GetCustomAttribute<AttributeUsageAttribute>();
    Console.WriteLine($"  Target: {attrUsage?.ValidOn}");
    Console.WriteLine($"  Properties: {string.Join(", ", attr.GetProperties().Where(p => p.CanRead).Select(p => p.Name))}");
}

Console.WriteLine("\n=== IHostBuilder Extensions (check what's available) ===");
var hostExt = AppDomain.CurrentDomain.GetAssemblies()
    .SelectMany(a => a.GetTypes())
    .Where(t => t.IsPublic && t.Name.EndsWith("Extensions"))
    .Where(t => t.GetMethods(BindingFlags.Public | BindingFlags.Static).Any(m => m.ReturnType.Name == "IHostBuilder"))
    .ToList();

Console.WriteLine($"Found {hostExt.Count} extension types for IHostBuilder-like configuration");

// Check what's in Microsoft.Extensions.Hosting
var hostingAsm = AppDomain.CurrentDomain.GetAssemblies().FirstOrDefault(a => a.GetName().Name == "Microsoft.Extensions.Hosting.Abstractions");
if (hostingAsm != null) {
    Console.WriteLine("\nHosting abstractions namespace types:");
    var hostingTypes = hostingAsm.GetTypes()
        .Where(t => t.Namespace == "Microsoft.Extensions.DependencyInjection" && t.IsPublic)
        .OrderBy(t => t.Name)
        .ToList();

    foreach (var t in hostingTypes.Take(10)) {
        Console.WriteLine($"  {t.Name}");
