using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

namespace McpServer.Tools;

[McpServerToolType]
public class ApiTools
{
    [McpServerTool(Name = "fetch_post"), Description("Fetches a post by ID from the external API.")]
    public static async Task<string> FetchPost(
        IHttpClientFactory httpClientFactory,
        ILogger<ApiTools> logger,
        [Description("The numeric ID of the post to fetch (1-100).")] int id)
    {
        logger.LogInformation("Fetching post {PostId}", id);

        var client = httpClientFactory.CreateClient("ExternalApi");
        var response = await client.GetAsync($"/posts/{id}");
        response.EnsureSuccessStatusCode();

        using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
        var result = new
        {
            id = doc.RootElement.GetProperty("id").GetInt32(),
            title = doc.RootElement.GetProperty("title").GetString(),
            body = doc.RootElement.GetProperty("body").GetString()
        };

        return JsonSerializer.Serialize(result, new JsonSerializerOptions { WriteIndented = true });
    }
}

using System.ComponentModel;
using ModelContextProtocol.Protocol;
using ModelContextProtocol.Server;

namespace McpServer.Prompts;

[McpServerPromptType]
public class SummarizationPrompts
{
    [McpServerPrompt(Name = "summarize"), Description("Generates a prompt that asks the model to summarize the given text.")]
    public static IList<PromptMessage> Summarize(
        [Description("The text content to summarize.")] string text,
        [Description("Desired length: 'short', 'medium', or 'long'. Defaults to 'medium'.")] string length = "medium")
    {
        var constraint = length switch
        {
            "short" => "in 1-2 sentences",
            "long" => "in a detailed multi-paragraph summary",
            _ => "in a concise paragraph"
        };

        return
        [
            new PromptMessage
            {
                Role = Role.User,
                Content = new Content
                {
                    Type = "text",
                    Text = $"Please summarize the following text {constraint}:\n\n{text}"
                }
            }
        ];
    }
}

